        cv_.notify_one();
        return id;
    }

    bool cancel(TaskID id) {
        std::lock_guard<std::mutex> lock(mutex_);

        auto it = tasks_.find(id);
        if (it == tasks_.end()) {
            return false;  // Already executed or doesn't exist
        }

        it->second->cancelled.store(true);  // Mark cancelled
        return true;
    }

    void worker_loop() {
        // ...
        if (!task->cancelled.load()) {
            task->func();
        }
        // ...
    }
};

