**Producer (push):**
```cpp
buffer_[tail] = item;  // Write data
tail_.store(new_tail, std::memory_order_release);  // Publish
```

**Consumer (pop):**
```cpp
size_t head = head_.load(std::memory_order_acquire);  // See latest
item = buffer_[head];
```

**Release-acquire** ensures visibility.

---



```cpp
#include <atomic>
#include <array>
#include <optional>

template<typename T, size_t SIZE>
class SPSCRingBuffer {
private:
    std::array<T, SIZE> buffer_;
    std::atomic<size_t> head_{0};
    std::atomic<size_t> tail_{0};

    size_t next_index(size_t current) const {
        return (current + 1) % SIZE;
    }

public:
    bool try_push(const T& item) {
        size_t current_tail = tail_.load(std::memory_order_relaxed);
        size_t next_tail = next_index(current_tail);

        if (next_tail == head_.load(std::memory_order_acquire)) {
            return false;  // Full
        }

        buffer_[current_tail] = item;
        tail_.store(next_tail, std::memory_order_release);

        return true;
    }

    std::optional<T> try_pop() {
        size_t current_head = head_.load(std::memory_order_relaxed);

        if (current_head == tail_.load(std::memory_order_acquire)) {
            return std::nullopt;  // Empty
        }

        T item = buffer_[current_head];
        head_.store(next_index(current_head), std::memory_order_release);

        return item;
    }

    bool empty() const {
        return head_.load(std::memory_order_acquire) ==
               tail_.load(std::memory_order_acquire);
    }

    bool full() const {
        return next_index(tail_.load(std::memory_order_acquire)) ==
               head_.load(std::memory_order_acquire);
    }

    size_t size() const {
        size_t h = head_.load(std::memory_order_acquire);
        size_t t = tail_.load(std::memory_order_acquire);

        if (t >= h) {
            return t - h;
        } else {
            return SIZE - h + t;
        }
    }
};
```

---

theory.full_text:
#### 1. Ring Buffer Basics

**Fixed-size circular queue:**
```
[_][_][_][_][_][_][_][_]
 ^head          ^tail
```

**Real-World Analogy: Conveyor Belt Sushi Restaurant**

```
CONVEYOR BELT (Ring Buffer):
┌────────────────────────────────────────────────┐
│         🍣  🍱  🍙  [ ]  [ ]  [ ]              │
│   ↓←←←←←←←←←←←←←←←←←←←←←←←←←←←←←←←               │
│   Consumer              Producer               │
│   takes sushi           adds sushi             │
│   (pop)                 (push)                 │
└────────────────────────────────────────────────┘

KEY FEATURES:
- Fixed number of plates (fixed size buffer)
- Producer adds sushi at one end
- Consumer takes sushi from other end
- Belt wraps around (circular/ring)
- No locks needed - they work on different ends!
```

**Operations:**
- `push(item)`: Producer puts new sushi plate on belt (write at tail, advance tail)
- `pop()`: Consumer takes sushi plate from belt (read at head, advance head)
- **Wrap-around:** When tail reaches end → wraps back to start (indices mod SIZE)

**Visual: Ring Buffer Structure**

```
CIRCULAR BUFFER (size = 8):

Initial state:
   head=0, tail=0 (empty)
┌───┬───┬───┬───┬───┬───┬───┬───┐
│ [ ]│[ ]│[ ]│[ ]│[ ]│[ ]│[ ]│[ ]│
└───┴───┴───┴───┴───┴───┴───┴───┘
 ↑
 head/tail

After 3 pushes:
   head=0, tail=3
┌───┬───┬───┬───┬───┬───┬───┬───┐
│ A │ B │ C │[ ]│[ ]│[ ]│[ ]│[ ]│
└───┴───┴───┴───┴───┴───┴───┴───┘
 ↑           ↑
 head       tail

After 5 more pushes (wraps around):
   head=0, tail=0 (FULL!)
┌───┬───┬───┬───┬───┬───┬───┬───┐
│ A │ B │ C │ D │ E │ F │ G │ H │
└───┴───┴───┴───┴───┴───┴───┴───┘
 ↑                               ↑
 head                           tail (wraps to 0)

After 2 pops:
   head=2, tail=0
┌───┬───┬───┬───┬───┬───┬───┬───┐
│[ ]│[ ]│ C │ D │ E │ F │ G │ H │
└───┴───┴───┴───┴───┴───┴───┴───┘
         ↑                       ↑
        head                   tail

After 2 more pushes (wraps):
   head=2, tail=2 (FULL again!)
┌───┬───┬───┬───┬───┬───┬───┬───┐
│ I │ J │ C │ D │ E │ F │ G │ H │
└───┴───┴───┴───┴───┴───┴───┴───┘
         ↑
       head/tail (full)
```

---

#### 2. Single Producer, Single Consumer (SPSC)

**Simplified:** Only one writer, one reader (most common).

**Key insight:** No contention between push/pop!

**Lock-free implementation:**
- `head_` (atomic, modified by consumer)
- `tail_` (atomic, modified by producer)

---

#### 3. Memory Ordering

**Producer (push):**
```cpp
buffer_[tail] = item;  // Write data
tail_.store(new_tail, std::memory_order_release);  // Publish
```

**Consumer (pop):**
```cpp
size_t head = head_.load(std::memory_order_acquire);  // See latest
item = buffer_[head];
```

**Release-acquire** ensures visibility.

---



```cpp
#include <atomic>
#include <array>
#include <optional>

template<typename T, size_t SIZE>
class SPSCRingBuffer {
private:
    std::array<T, SIZE> buffer_;
    std::atomic<size_t> head_{0};
    std::atomic<size_t> tail_{0};

    size_t next_index(size_t current) const {
        return (current + 1) % SIZE;
    }

public:
    bool try_push(const T& item) {
        size_t current_tail = tail_.load(std::memory_order_relaxed);
        size_t next_tail = next_index(current_tail);

        if (next_tail == head_.load(std::memory_order_acquire)) {
            return false;  // Full
        }

        buffer_[current_tail] = item;
        tail_.store(next_tail, std::memory_order_release);

        return true;
    }

    std::optional<T> try_pop() {
        size_t current_head = head_.load(std::memory_order_relaxed);

        if (current_head == tail_.load(std::memory_order_acquire)) {
            return std::nullopt;  // Empty
        }

        T item = buffer_[current_head];
        head_.store(next_index(current_head), std::memory_order_release);

        return item;
    }

    bool empty() const {
        return head_.load(std::memory_order_acquire) ==
               tail_.load(std::memory_order_acquire);
    }

    bool full() const {
        return next_index(tail_.load(std::memory_order_acquire)) ==
               head_.load(std::memory_order_acquire);
    }

    size_t size() const {
        size_t h = head_.load(std::memory_order_acquire);
        size_t t = tail_.load(std::memory_order_acquire);

        if (t >= h) {
            return t - h;
        } else {
            return SIZE - h + t;
        }
    }
};
```

